88	struct RequestAbortGuard {
89	    bridge: Arc<PyBridge>,
90	    rid: String,
91	    armed: bool,
92	}
93	
94	impl RequestAbortGuard {
95	    fn new(bridge: Arc<PyBridge>, rid: impl Into<String>) -> Self {
96	        Self {
97	            bridge,
98	            rid: rid.into(),
99	            armed: true,
100	        }
101	    }
102	
103	    fn disarm(&mut self) {
104	        self.armed = false;
105	    }
106	
107	    fn abort_now(&mut self) {
108	        if self.armed {
109	            self.armed = false;
110	            spawn_abort(self.bridge.clone(), self.rid.clone());
111	        }
112	    }
113	}
114	
115	impl Drop for RequestAbortGuard {
116	    fn drop(&mut self) {
117	        if self.armed {
118	            // Dropping a response stream means the client stopped consuming; propagate
119	            // cancellation to Python without blocking the Tokio worker.
120	            spawn_abort(self.bridge.clone(), self.rid.clone());
121	        }
122	    }
123	}
124	
125	fn spawn_abort(bridge: Arc<PyBridge>, rid: String) {
126	    match tokio::runtime::Handle::try_current() {
127	        Ok(handle) => {
128	            let _ = handle.spawn_blocking(move || {
129	                let _ = bridge.abort(&rid, false);
130	            });
131	        }
132	        Err(_) => {
133	            tracing::warn!(
134	                rid,
135	                "Skipping gRPC request abort because no Tokio runtime is available"
136	            );
137	        }
138	    }
139	}
140	
141	async fn recv_terminal_chunk_for_request(
142	    bridge: &Arc<PyBridge>,
143	    rid: &str,
144	    receiver: &mut Receiver<ResponseChunk>,
145	    response_timeout: Duration,
146	) -> Result<ResponseChunk, Status> {
147	    let mut abort_guard = RequestAbortGuard::new(bridge.clone(), rid.to_string());
148	
149	    match recv_chunk_with_timeout(receiver, response_timeout, || {
150	        format!("Request timed out after {}s", response_timeout.as_secs())
151	    })
152	    .await
153	    {
154	        Ok(Some(ResponseChunk::Data(_))) => {
155	            tracing::warn!(
156	                rid,
157	                "Unary gRPC response received non-terminal Data chunk; expected Finished"
158	            );
159	            abort_guard.abort_now();
160	            Err(Status::internal(
161	                "Unary response protocol violation: expected Finished, got Data",
162	            ))
163	        }
164	        Ok(Some(chunk @ (ResponseChunk::Finished(_) | ResponseChunk::Error(_)))) => {
165	            abort_guard.disarm();
166	            Ok(chunk)
167	        }
168	        Ok(None) => {
169	            let (status, should_abort) = closed_stream_status(bridge, rid);
170	            if should_abort {
171	                abort_guard.abort_now();
172	            } else {
173	                abort_guard.disarm();
174	            }
175	            Err(status)
176	        }
177	        Err(status) => {
178	            if status.code() == tonic::Code::DeadlineExceeded {
179	                abort_guard.abort_now();
180	            } else {
181	                abort_guard.disarm();
182	            }
183	            Err(status)
184	        }
185	    }
186	}
