973	/// Start the Tonic gRPC server on the given address.
974	//
975	// TODO(grpc-auth): this listener is currently unauthenticated. Before exposing
976	// it in any default deploy path, gate it with the same API-key / admin-key
977	// checks the HTTP server applies (see issue tracking gRPC auth parity).
978	pub async fn run_grpc_server(
979	    listener: std::net::TcpListener,
980	    bridge: Arc<PyBridge>,
981	    shutdown: Arc<Notify>,
982	    response_timeout: Duration,
983	) -> Result<(), Box<dyn std::error::Error + Send + Sync>> {
984	    let addr = listener.local_addr()?;
985	    let listener = tokio::net::TcpListener::from_std(listener)?;
986	    let service = SglangServiceImpl {
987	        bridge,
988	        response_timeout,
989	    };
990	
991	    let max_message_size = resolve_max_message_size();
992	    let svc = proto::sglang_service_server::SglangServiceServer::new(service)
993	        .max_decoding_message_size(max_message_size)
994	        .max_encoding_message_size(max_message_size);
995	
996	    tracing::info!("gRPC server listening on {}", addr);
997	
998	    tonic::transport::Server::builder()
